let state = null;

export function initialize(wrapper, dotNetRef, timeoutMs) {
    const s = {
        wrapper,
        dotNetRef,
        timeoutMs,
        timerId: null,
        isIdle: false,
        handler: null,
    };

    s.handler = () => {
        if (s.isIdle) {
            s.isIdle = false;
            s.dotNetRef.invokeMethodAsync("OnActiveCallback");
        }
        resetTimer(s);
    };

    const events = ["mousemove", "keydown", "click", "scroll"];
