    if (s.timerId !== null) {
        clearTimeout(s.timerId);
    }
    s.timerId = setTimeout(() => {
        s.isIdle = true;
        s.dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, s.timeoutMs);
}

export function dispose() {
    if (!state) return;
    const s = state;

    if (s.timerId !== null) {
        clearTimeout(s.timerId);
        s.timerId = null;
    }

    const events = s.events;
    events.forEach(e => s.wrapper.removeEventListener(e, s.handler));
    events.forEach(e => document.removeEventListener(e, s.handler));

    state = null;
}

